                onChange={(e) => setFormData({...formData, content: e.target.value})}
                placeholder="간략한 고민 내용을 적어주시면 더 정확한 상담이 가능합니다."
                className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all text-sm resize-none"
