import React, { useState, useEffect } from 'react';

interface ConsultationPopupProps {
  onClose: () => void;
}

const ConsultationPopup: React.FC<ConsultationPopupProps> = ({ onClose }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    content: ''
  });

  const WEBHOOK_URL = ""; 

  useEffect(() => {
    const timer = setTimeout(() => setIsVisible(true), 800);
    return () => clearTimeout(timer);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSending(true);

    try {
      if (WEBHOOK_URL) {
        const response = await fetch(WEBHOOK_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            content: "🚨 **[팝업] 새로운 상담 예약이 도착했습니다!**",
            embeds: [{
              title: "팝업 상담 신청 내역",
              color: 16753920,
              fields: [
                { name: "👤 의뢰인", value: formData.name, inline: true },
                { name: "📞 연락처", value: formData.phone, inline: true },
                { name: "💬 상담내용", value: formData.content || "내용 없음" }
              ],
              timestamp: new Date().toISOString()
            }]
          })
        });
        if (!response.ok) throw new Error('전송 실패');
      } else {
        await new Promise(resolve => setTimeout(resolve, 1000));
      }

      alert(`${formData.name}님, 상담 예약이 정상적으로 접수되었습니다. 담당 변호사가 확인 후 즉시 연락드리겠습니다.`);
      onClose();
