const LocationSection: React.FC = () => {
  const mapTimestamp = "1766998727608";
  const mapKey = "epnbi79isje";
  const containerId = `daumRoughmapContainer${mapTimestamp}`;

  useEffect(() => {
    // 카카오 지도 스크립트 로드 함수
    const loadKakaoMap = () => {
      const scriptId = 'kakao-roughmap-loader';

      if (!document.getElementById(scriptId)) {
        const script = document.createElement('script');
        script.id = scriptId;
        script.src = 'https://ssl.daumcdn.net/dmaps/map_js_init/roughmapLoader.js';
        script.charset = 'UTF-8';
        script.onload = () => {
          renderMap();
        };
        document.head.appendChild(script);
      } else {
        // 스크립트가 이미 로드된 경우 바로 렌더링 시도
        if (window.daum && window.daum.roughmap) {
          renderMap();
        }
      }
