import React, { useState, useEffect } from 'react';
import { SuccessCase } from '../types';

interface AdminDashboardProps {
  onClose: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onClose }) => {
  const [cases, setCases] = useState<SuccessCase[]>([]);
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<SuccessCase>>({
    category: '성범죄',
    title: '',
    date: new Date().toISOString().split('T')[0],
    summary: '',
    solution: '',
    result: '',
    image: ''
  });

  useEffect(() => {
    const saved = localStorage.getItem('an_law_cases');
    if (saved) setCases(JSON.parse(saved));
  }, []);

  const saveToLocal = (newCases: SuccessCase[]) => {
    localStorage.setItem('an_law_cases', JSON.stringify(newCases));
    setCases(newCases);
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      const updated = cases.map(c => c.id === editingId ? { ...formData, id: editingId } as SuccessCase : c);
      saveToLocal(updated);
    } else {
      const newCase = { ...formData, id: Date.now().toString() } as SuccessCase;
      saveToLocal([newCase, ...cases]);
    }
    resetForm();
    alert('저장되었습니다. 페이지를 새로고침하면 반영됩니다.');
    window.location.reload();
  };

  const handleDelete = (id: string) => {
    if (window.confirm('정말 삭제하시겠습니까?')) {
      const filtered = cases.filter(c => c.id !== id);
      saveToLocal(filtered);
      window.location.reload();
    }
  };

  const resetForm = () => {
    setIsAdding(false);
    setEditingId(null);
    setFormData({
      category: '성범죄',
      title: '',
      date: new Date().toISOString().split('T')[0],
      summary: '',
      solution: '',
      result: '',
      image: ''
    });
  };

  const copyJSON = () => {
    navigator.clipboard.writeText(JSON.stringify(cases, null, 2));
    alert('데이터가 클립보드에 복사되었습니다. 개발자에게 전달하여 영구 반영할 수 있습니다.');
  };

  return (
    <div className="fixed inset-0 z-[200] bg-slate-900/90 backdrop-blur-md overflow-y-auto p-4 md:p-8">
      <div className="max-w-5xl mx-auto bg-white rounded-[2.5rem] shadow-2xl overflow-hidden min-h-[80vh]">
        <div className="bg-slate-800 p-8 text-white flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-black">성공 사례 관리자 패널</h2>
            <p className="text-slate-400 text-sm">여기에서 등록한 내용은 브라우저에 즉시 저장됩니다.</p>
          </div>
          <div className="flex gap-3">
            <button onClick={copyJSON} className="px-4 py-2 bg-slate-700 hover:bg-slate-600 rounded-xl text-xs font-bold transition-all">전체 데이터 복사</button>
            <button onClick={onClose} className="p-2 bg-white/10 hover:bg-white/20 rounded-full transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
        </div>

        <div className="p-8">
          {!isAdding && !editingId ? (
            <div className="space-y-6">
              <button 
                onClick={() => setIsAdding(true)}
                className="w-full py-4 border-2 border-dashed border-slate-200 rounded-3xl text-slate-400 font-bold hover:border-amber-500 hover:text-amber-600 transition-all"
              >
                + 새로운 성공 사례 추가하기
              </button>

              <div className="grid grid-cols-1 gap-4">
                {cases.map(c => (
                  <div key={c.id} className="p-6 bg-slate-50 rounded-2xl border border-slate-100 flex justify-between items-center group">
                    <div className="flex gap-4 items-center">
                      {c.image && <div className="w-12 h-12 rounded-lg bg-slate-200 overflow-hidden shrink-0"><img src={c.image} className="w-full h-full object-cover" /></div>}
                      <div>
                        <span className="text-[10px] font-bold text-amber-600 bg-amber-50 px-2 py-0.5 rounded">{c.category}</span>
                        <h4 className="font-black text-slate-800">{c.title}</h4>
                        <p className="text-xs text-slate-400">{c.date}</p>
                      </div>
                    </div>
                    <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={() => { setEditingId(c.id); setFormData(c); }}
                        className="px-4 py-2 bg-blue-100 text-blue-700 text-xs font-bold rounded-xl hover:bg-blue-200 transition-all"
                      >수정</button>
                      <button 
                        onClick={() => handleDelete(c.id)}
                        className="px-4 py-2 bg-red-100 text-red-700 text-xs font-bold rounded-xl hover:bg-red-200 transition-all"
                      >삭제</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-6 animate-in slide-in-from-bottom-4 duration-300">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">분류</label>
                  <select 
                    value={formData.category}
                    onChange={e => setFormData({...formData, category: e.target.value})}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none"
                  >
                    <option>성범죄</option>
                    <option>형사</option>
                    <option>이혼</option>
                    <option>민사</option>
                    <option>상속</option>
                    <option>경제/마약</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">날짜</label>
                  <input 
                    type="date"
                    required
                    value={formData.date}
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">제목</label>
                <input 
                  type="text"
                  required
                  placeholder="예: 강제추행 무혐의 처분 성공"
                  value={formData.title}
                  onChange={e => setFormData({...formData, title: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none"
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">사건 개요</label>
                  <textarea 
                    rows={4}
                    required
                    value={formData.summary}
                    onChange={e => setFormData({...formData, summary: e.target.value})}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none resize-none text-sm"
                  ></textarea>
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">'安'의 조력</label>
                  <textarea 
                    rows={4}
                    required
                    value={formData.solution}
                    onChange={e => setFormData({...formData, solution: e.target.value})}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none resize-none text-sm"
                  ></textarea>
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">결과</label>
                  <textarea 
                    rows={4}
                    required
                    value={formData.result}
                    onChange={e => setFormData({...formData, result: e.target.value})}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none resize-none text-sm"
                  ></textarea>
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">판결문 이미지 업로드 (최대 1개)</label>
                <div className="flex items-center gap-6">
                  <input 
                    type="file" 
                    accept="image/*"
                    onChange={handleImageChange}
                    className="text-xs text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-black file:bg-slate-100 file:text-slate-700 hover:file:bg-slate-200"
                  />
                  {formData.image && (
                    <div className="relative w-24 h-24 rounded-xl border overflow-hidden">
                       <img src={formData.image} className="w-full h-full object-cover" />
                       <button onClick={() => setFormData({...formData, image: ''})} className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full"><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>
                  )}
                </div>
              </div>

              <div className="flex gap-4 pt-6 border-t">
                <button type="submit" className="flex-1 py-4 bg-blue-900 text-white font-black rounded-2xl shadow-lg hover:bg-blue-800 transition-all">저장하기</button>
                <button type="button" onClick={resetForm} className="px-10 py-4 bg-slate-100 text-slate-500 font-bold rounded-2xl hover:bg-slate-200 transition-all">취소</button>
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

