const ContactForm: React.FC = () => {
  const [isSending, setIsSending] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    category: '선택해 주세요',
    content: '',
    privacy: false
  });

  // 제공된 n8n 웹후크 URL 적용
  const WEBHOOK_URL = "https://lawahn79.app.n8n.cloud/webhook-test/3d332dc2-1f72-412c-82d5-5a7ff029dc10"; 

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'checkbox' ? (e.target as HTMLInputElement).checked : value;
    setFormData(prev => ({ ...prev, [name]: val }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.privacy) {
      alert('개인정보 수집 및 이용에 동의해주세요.');
      return;
    }

    setIsSending(true);

    try {
      if (WEBHOOK_URL) {
        const response = await fetch(WEBHOOK_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            content: "🔔 **새로운 법률상담 예약이 도착했습니다!**",
            embeds: [{
              title: "상담 신청 상세 내역",
              color: 15844367,
              fields: [
                { name: "👤 성함", value: formData.name, inline: true },
                { name: "📞 연락처", value: formData.phone, inline: true },
                { name: "⚖️ 상담분야", value: formData.category, inline: true },
                { name: "💬 문의내용", value: formData.content }
              ],
              footer: { text: "법률사무소 安 - 실시간 알림 시스템" },
              timestamp: new Date().toISOString()
            }]
          })
        });

        if (!response.ok) throw new Error('전송 실패');
      } else {
        await new Promise(resolve => setTimeout(resolve, 1500));
      }

      setSubmitted(true);
    } catch (error) {
      console.error(error);
      alert('알림 전송 중 오류가 발생했습니다. 하지만 데이터는 기록되었습니다.');
    } finally {
      setIsSending(false);
    }
  };

  if (submitted) {
    return (
      <section id="consultation-form" className="py-24 bg-white scroll-mt-24">
        <div className="container mx-auto px-6 text-center">
          <div className="max-w-xl mx-auto p-12 bg-slate-50 rounded-3xl border border-amber-100 shadow-xl animate-in zoom-in-95 duration-500">
