      <div className="bg-white w-full max-w-4xl max-h-[90vh] md:max-h-[85vh] rounded-[2rem] md:rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row relative animate-in slide-in-from-bottom-8 duration-700">

        {isSending && (
          <div className="absolute inset-0 bg-white/70 backdrop-blur-sm z-[110] flex flex-col items-center justify-center p-6 text-center">
            <div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-blue-900 font-black">상담 내용을 안전하게 전송 중입니다...</p>
          </div>
        )}

        <button 
          onClick={onClose}
          className="absolute top-4 right-4 md:top-6 md:right-6 z-[120] p-2 bg-slate-100/50 md:bg-transparent hover:bg-slate-200 md:hover:bg-white/10 rounded-full text-slate-900 md:text-slate-400 hover:text-slate-900 md:hover:text-white transition-all shadow-sm md:shadow-none"
          aria-label="Close popup"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 md:h-8 md:w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>

        <div className="w-full h-full flex flex-col md:flex-row overflow-y-auto outline-none">
          <div className="md:w-5/12 bg-blue-950 p-8 md:p-10 text-white flex flex-col justify-between relative shrink-0">
            <div className="absolute top-0 right-0 w-48 h-48 bg-amber-500/10 rounded-full blur-[60px] -translate-y-1/2 translate-x-1/2 hidden md:block"></div>

            <div className="relative z-10">
              <div className="flex items-center gap-2 md:gap-3 mb-4 md:mb-6">
                <div className="text-amber-500 font-serif text-3xl md:text-5xl leading-none">安</div>
                <div className="text-white text-sm md:text-lg font-black tracking-tight">법률사무소 '安'</div>
              </div>

              <h3 className="text-2xl md:text-3xl font-black mb-3 md:mb-4 leading-tight">
                당신의 평안을 위한<br />
                <span className="text-amber-500">24시 무료상담</span>
              </h3>
              <p className="text-slate-400 text-xs md:text-sm leading-relaxed mb-6 md:mb-8 max-w-xs">
                혼자 고민하지 마세요. 형사·이혼 전문 변호사가 직접 사건을 검토합니다.
              </p>

              <ul className="space-y-2 md:space-y-4 mb-6 md:mb-0">
                {['형사/성범죄 전문', '이혼/재산분할 전문', '1:1 비밀보장 상담'].map((text, i) => (
                  <li key={i} className="flex items-center gap-2 md:gap-3 text-[11px] md:text-sm font-bold text-slate-200">
                    <span className="w-4 h-4 md:w-5 md:h-5 rounded-full bg-amber-600 flex items-center justify-center text-[8px] md:text-[10px]">✓</span>
                    {text}
                  </li>
                ))}
              </ul>
            </div>

            <a 
              href="tel:010-4679-0325" 
              className="mt-4 md:mt-8 relative z-10 block transition-all hover:scale-[1.02] active:scale-95 group"
            >
              <div className="bg-white/10 p-3 md:p-4 rounded-xl md:rounded-2xl border border-white/10 group-hover:bg-white/20 transition-colors">
                <div className="text-[9px] md:text-[10px] text-amber-500 font-bold uppercase tracking-widest mb-1">Direct Call</div>
                <div className="text-lg md:text-xl font-black text-white">010-4679-0325</div>
              </div>
              <div className="mt-1.5 md:mt-2 text-[9px] md:text-[10px] text-center text-slate-400 font-bold group-hover:text-amber-500 transition-colors">
                클릭 시 바로 전화 연결됩니다
              </div>
            </a>
          </div>

          <div className="md:w-7/12 p-8 md:p-14 bg-white flex flex-col justify-center">
            <div className="mb-6 md:mb-8">
              <span className="inline-block px-2 py-0.5 bg-amber-100 text-amber-700 text-[9px] md:text-[10px] font-black uppercase tracking-wider mb-2 rounded">Quick Contact</span>
              <h4 className="text-xl md:text-2xl font-black text-slate-900 tracking-tighter">간편 상담 예약 신청</h4>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4 md:space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="block text-[11px] font-bold text-slate-500 ml-1">의뢰인 성함</label>
                  <input 
                    type="text" 
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    placeholder="성함 입력"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all text-sm"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="block text-[11px] font-bold text-slate-500 ml-1">연락처</label>
                  <input 
                    type="tel" 
                    value={formData.phone}
                    onChange={(e) => setFormData({...formData, phone: e.target.value})}
                    placeholder="010-0000-0000"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all text-sm"
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="block text-[11px] font-bold text-slate-500 ml-1">상담 내용 (선택)</label>
                <textarea 
                  rows={2}
                  value={formData.content}
                  onChange={(e) => setFormData({...formData, content: e.target.value})}
                  placeholder="고민 내용을 적어주세요."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all text-sm resize-none"
                ></textarea>
              </div>

              <div className="flex items-start gap-2 mb-4 ml-1">
                <input type="checkbox" id="popup-privacy-check" required className="mt-1 accent-amber-600 w-4 h-4 shrink-0" />
                <label htmlFor="popup-privacy-check" className="text-[10px] md:text-[11px] text-slate-400 leading-tight cursor-pointer">
                  개인정보 수집 및 이용(비밀보장)에 동의합니다.
                </label>
              </div>

              <button 
                type="submit"
                disabled={isSending}
                className="w-full py-4 bg-blue-900 text-white font-black rounded-xl hover:bg-blue-800 transition-all shadow-lg active:scale-[0.98] disabled:bg-slate-400"
              >
                {isSending ? '전송 중...' : '상담 예약 신청하기'}
              </button>
              <p className="text-center text-[9px] md:text-[10px] text-slate-400">
                * 접수 즉시 담당 변호사에게 실시간 알림이 전송됩니다.
              </p>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ConsultationPopup;
